sprite_code.bg:
// Mystical twilight forest sky
for(var y=0;y<85;y++) for(var x=0;x<PW;x++){
  var g=y/85;
  px(x,y, Math.floor(60+g*40), Math.floor(45+g*30), Math.floor(90+g*45), 'sky');
}
// Glowing spores (embers)
for(var i=0;i<20;i++){
  var sx=Math.floor(Math.random()*PW), sy=Math.floor(Math.random()*80);
  px(sx,sy, 255,220,100, 'sky');
}
// Bioluminescent ground (teal to neon green)
for(var y=85;y<PH;y++) for(var x=0;x<PW;x++){
  var n=Math.sin(x*0.1+y*0.15)*5+Math.sin(x*0.05)*3;
  var r=Math.floor(20+n), g=Math.floor(120+n*10), b=Math.floor(80+n);
  px(x,y, r*0.5, g, b*0.6, 'ground');
}
// Horizon moss tufts
for(var x=0;x<PW;x+=4){
  var gy=84+Math.floor(Math.sin(x*0.05)*4);
  circ(x, gy, 3, 50, 200, 100, 'ground');
}

sprite_code.fox_01:
const eid = 'fox_01';
const cx = 60, cy = 115;
// Body: standing on hind legs, stretched upward
ellip(cx, cy, 6, 11, 200, 80, 48, eid+'.body');
ellip(cx, cy, 5, 9, 215, 100, 60, eid+'.body');
// White belly patch
ellip(cx-2, cy-2, 3, 5, 235, 200, 160, eid+'.body.belly');
// Head: tilted up
circ(cx+2, cy-14, 6, 205, 85, 50, eid+'.head');
circ(cx+2, cy-14, 5, 220, 100, 60, eid+'.head');
// Snout
ellip(cx+7, cy-13, 3, 2, 235, 200, 160, eid+'.head.snout');
px(cx+9, cy-14, 35, 20, 15, eid+'.head.nose');
// Eyes: sapphire blue scarf detail later, eyes are dark
circ(cx+4, cy-16, 1, 15, 10, 8, eid+'.head.eyes');
px(cx+4, cy-17, 255, 255, 255, eid+'.head.eyes');
// Large tufted ears
tri(cx-1, cy-18, cx+1, cy-26, cx+4, cy-19, 200, 80, 48, eid+'.head.ears.left');
tri(cx+3, cy-18, cx+5, cy-26, cx+8, cy-19, 200, 80, 48, eid+'.head.ears.right');
// Sapphire-blue scarf
rect(cx-1, cy-10, 7, 2, 30, 80, 200, eid+'.scarf');
line(cx-2, cy-9, cx-5, cy-5, 40, 100, 220, eid+'.scarf.tail');
// Legs: charcoal paws
rect(cx-4, cy+8, 2, 6, 40, 40, 45, eid+'.legs.back_left');
rect(cx+2, cy+8, 2, 6, 40, 40, 45, eid+'.legs.back_right');
// Front paw reaching up
thickLine(cx+4, cy-5, cx+10, cy-10, 2, 200, 80, 48, eid+'.legs.front_right');
rect(cx+9, cy-11, 3, 2, 40, 40, 45, eid+'.legs.front_right.paw');
// Tail: white-tipped
ellip(cx-8, cy+5, 4, 8, 200, 80, 48, eid+'.tail');
circ(cx-10, cy+11, 3, 240, 210, 170, eid+'.tail.tip');

sprite_code.tree_01:
const eid = 'tree_01';
const cx = 180, cy = 100;
// Roots
for(var i=0;i<3;i++){
  thickLine(cx-15+i*10, cy+30, cx-25+i*20, cy+45, 3, 70, 70, 75, eid+'.roots');
}
// Trunk: weathered silver-grey
rect(cx-15, cy-20, 30, 60, 90, 90, 95, eid+'.trunk');
rect(cx-12, cy-20, 24, 60, 110, 110, 115, eid+'.trunk');
// Swirling knots (eyes)
circ(cx-5, cy+5, 2, 60, 60, 65, eid+'.trunk.knots');
circ(cx+7, cy-5, 2, 60, 60, 65, eid+'.trunk.knots');
// Mossy patches
for(var i=0;i<8;i++){
  circ(cx-12+Math.random()*24, cy-20+Math.random()*50, 3, 50, 120, 60, eid+'.trunk.moss');
}
// Glowing blue fungi
circ(cx-14, cy, 3, 60, 150, 255, eid+'.fungi');
circ(cx-14, cy-1, 2, 130, 200, 255, eid+'.fungi');
circ(cx+14, cy+10, 3, 60, 150, 255, eid+'.fungi');
// Branches: curving downward
thickLine(cx-15, cy-15, cx-40, cy, 4, 80, 80, 85, eid+'.branches');
thickLine(cx+15, cy-15, cx+40, cy, 4, 80, 80, 85, eid+'.branches');
// Canopy
ellip(cx, cy-35, 40, 20, 40, 80, 40, eid+'.canopy');
ellip(cx, cy-40, 35, 15, 55, 110, 55, eid+'.canopy');
circ(cx-20, cy-45, 10, 70, 140, 70, eid+'.canopy.highlight');

sprite_code.lantern_01:
