px(cx, cy, 255, 255, 255, eid+'.detail');
// Sparkle trail
px(cx+5, cy+5, 255, 255, 200, eid+'.sparkles');
px(cx+8, cy+8, 255, 255, 200, eid+'.sparkles');
px(cx+3, cy+10, 255, 255, 200, eid+'.sparkles');

